using UnityEngine;

/// <summary>
/// Eco Perdido — coleccionável escondido nas fases (exploração ou puzzles).
///
/// Serve de moeda para comprar <b>Sussurros da Terra</b> no
/// <b>Contador de Histórias</b> (NPC especial de cada área).
///
/// Regras de design (GDD):
/// - Cada área normal tem normalmente <b>15 Ecos Perdidos</b>, pois os
///   5 Sussurros disponíveis têm preços crescentes: 1, 2, 3, 4 e 5 Ecos.
/// - Áreas de <b>Vila</b> e de <b>Boss</b> NÃO têm Ecos Perdidos
///   (não há Contador de Histórias nessas áreas).
/// - Ficam escondidos — exigem exploração ou resolução de pequenos puzzles.
///
/// Ao recolher:
/// - Regista o eco como encontrado nesta área (AreaProgress.ecosPerdidosFound /
///   AreaData.totalEcosPerdidos) — limitado ao total da área.
/// - Dá +1 ao saldo global do jogador (PlayerProgress.GiveEcosPerdidos →
///   ecosPerdidos / totalEcosPerdidosCollected).
/// </summary>
public class EcoPerdidoPickup : PickupBase
{
    public override PickupType Type => PickupType.EcoPerdido;

    protected override void GrantReward()
    {
        // AddEcoPerdidoFound já chama GiveEcosPerdidos(1) internamente.
        if (area != null)
            PlayerProgress.Instance?.AddEcoPerdidoFound(area);
        else
            PlayerProgress.Instance?.GiveEcosPerdidos(1);
    }
}
